**Part (b) — Vowel/Consonant Counter (7 Marks)**

```java
import java.io.*;

public class VowelConsonantCount {
    public static void main(String[] args) {
        int vowels = 0, consonants = 0;

        try (FileReader fr = new FileReader("input.txt")) {
            int ch;
            // 1 mark — opening stream
            // 1 mark — read loop using read() which returns int (0-65535) or -1
            while ((ch = fr.read()) != -1) {
                char c = Character.toLowerCase((char) ch);
                if (c >= 'a' && c <= 'z') {
                    if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u')
                        vowels++;       // 1 mark
                    else
                        consonants++;   // 1 mark
                }
            }
            // 1 mark — try-with-resources for auto-close
        } catch (FileNotFoundException e) {
            System.err.println("File not found: " + e.getMessage());
        } catch (IOException e) {
            System.err.println("I/O Error: " + e.getMessage());
        }

        // 1 mark — display results
        System.out.println("Vowels     : " + vowels);
        System.out.println("Consonants : " + consonants);
    }
}
```

