**Part (b) — Append File Using Byte Streams (7 Marks)**

```java
import java.io.*;

public class FileAppend {
    public static void main(String[] args) {
        String source = "source.txt";
        String destination = "destination.txt";

        // 1 mark — using FileInputStream + FileOutputStream with append=true
        try (FileInputStream fis = new FileInputStream(source);
             FileOutputStream fos = new FileOutputStream(destination, true)) {

            int b;
            // 1 mark — read loop returning -1 at EOF
            while ((b = fis.read()) != -1) {
                fos.write(b);   // 1 mark — write each byte
            }

            System.out.println("File appended successfully.");  // 1 mark

        } catch (FileNotFoundException e) {
            // 1 mark — exception handling
            System.err.println("Source file not found: " + e.getMessage());
        } catch (IOException e) {
            System.err.println("I/O Error: " + e.getMessage());
        }
        // 1 mark — try-with-resources for auto-close
    }
}
```

